// Lookup returns the best replacement for a 2-instruction sequence,
// or nil if no optimization is known.
func Lookup(source string) *Rule {
	if r, ok := Top500[source]; ok { return &r }
	return nil
}

// LoadRules loads peephole rules from a JSON file.
// Format: [{"source": "...", "replacement": "...", "cycles_saved": N, "bytes_saved": N}]
func LoadRules(path string) (map[string]Rule, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, err
	}
	var entries []struct {
		Source      string `json:"source"`
		Replacement string `json:"replacement"`
		CyclesSaved int    `json:"cycles_saved"`
		BytesSaved  int    `json:"bytes_saved"`
	}
	if err := json.Unmarshal(data, &entries); err != nil {
		return nil, err
	}
	rules := make(map[string]Rule, len(entries))
	for _, e := range entries {
		rules[e.Source] = Rule{e.Replacement, e.CyclesSaved, e.BytesSaved}
	}
	return rules, nil
}
